<section class="page-head"><h1>Pedidos</h1><p>Consultas guardadas. Solo los pedidos aceptados como vendidos afectan contabilidad.</p></section><div class="panel"><div class="table-responsive"><table class="admin-table"><thead><tr><th>ID</th><th>Fecha</th><th>Producto</th><th>Estado</th><th>Mensaje</th><th>Acciones</th></tr></thead><tbody><?php foreach($pedidos as $p): ?><tr><td>#<?= e($p['id']) ?></td><td><?= e($p['created_at'] ?? '-') ?></td><td><strong><?= e($p['producto_titulo'] ?? '-') ?></strong><small><?= isset($p['producto_id'])?'#'.e($p['producto_id']):'' ?></small></td><td><span class="badge-soft"><?= e($p['estado'] ?? '-') ?></span></td><td><?= e(mb_strimwidth($p['mensaje'] ?? '',0,100,'...')) ?></td><td><div class="pedido-actions"><form method="post" action="<?= site_url('admin/pedidos/estado/'.$p['id']) ?>"><?= csrf_field() ?><input type="hidden" name="estado" value="vendido"><button class="btn small primary">Vendido</button></form><form method="post" action="<?= site_url('admin/pedidos/estado/'.$p['id']) ?>"><?= csrf_field() ?><input type="hidden" name="estado" value="no_vendido"><button class="btn small">No vendido</button></form><form method="post" action="<?= site_url('admin/pedidos/eliminar/'.$p['id']) ?>" onsubmit="return confirm('Esto elimina el pedido de la base. ¿Seguro?')"><?= csrf_field() ?><button class="btn small">Eliminar</button></form></div></td></tr><?php endforeach; ?></tbody></table></div></div>
